const body = ($input.first() && $input.first().json && $input.first().json.body) || {};
const client = String(body.client || '').trim();
if (!client || !/^[A-Za-z0-9&_-]{1,80}$/.test(client)) throw new Error('valid client required');
const items = Array.isArray(body.items) ? body.items : [];
if (items.length === 0) throw new Error('items[] required');
const clean = items.map(it => {
  const id = String(it.id || '').trim();
  if (!id) throw new Error('every item needs an id');
  const order_index = Number(it.order_index);
  if (!Number.isFinite(order_index)) throw new Error('every item needs a numeric order_index');
  return { id, order_index };
});
const sheetName = 'Calendar_' + client;
const base = 'https://sheets.googleapis.com/v4/spreadsheets/1Gsn5xLImJyMhBMCNjK_tigpoUfcSFnvxTQLkk-A9Yps';
return [{ json: {
  sheetName,
  items: clean,
  now: new Date().toISOString(),
  headersUrl: base + '/values/' + encodeURIComponent("'" + sheetName + "'!1:1"),
  base
} }];

const plan = $('Validate & Plan').first().json;
const resp = $input.first().json || {};
const headers = ((resp.values || [])[0] || []).map(h => String(h || '').trim());
if (!headers.length) throw new Error('sheet ' + plan.sheetName + ' has no header row');
const colA1 = (i) => { let s = ''; i += 1; while (i > 0) { const m = (i - 1) % 26; s = String.fromCharCode(65 + m) + s; i = Math.floor((i - 1) / 26); } return s; };
const idIdx = headers.indexOf('id');
const orderIdx = headers.indexOf('order_index');
const updatedIdx = headers.indexOf('updated_at');
if (idIdx < 0) throw new Error('no id column in ' + plan.sheetName);
if (orderIdx < 0) throw new Error('no order_index column in ' + plan.sheetName);
const idCol = colA1(idIdx);
return [{ json: {
  idColUrl: plan.base + '/values/' + encodeURIComponent("'" + plan.sheetName + "'!" + idCol + ':' + idCol),
  orderCol: colA1(orderIdx),
  updatedCol: updatedIdx >= 0 ? colA1(updatedIdx) : null
} }];

const plan = $('Validate & Plan').first().json;
const cols = $('Find Columns').first().json;
const resp = $input.first().json || {};
const colVals = resp.values || [];
const rowById = new Map();
for (let i = 1; i < colVals.length; i++) {
  const v = String((colVals[i] || [])[0] || '').trim();
  if (v && !rowById.has(v)) rowById.set(v, i + 1);
}
const data = [];
const skipped = [];
for (const it of plan.items) {
  const row = rowById.get(it.id);
  if (!row) { skipped.push(it.id); continue; }
  data.push({ range: "'" + plan.sheetName + "'!" + cols.orderCol + row, values: [[String(it.order_index)]] });
  if (cols.updatedCol) data.push({ range: "'" + plan.sheetName + "'!" + cols.updatedCol + row, values: [[plan.now]] });
}
return [{ json: {
  url: plan.base + '/values:batchUpdate',
  payload: { valueInputOption: 'RAW', data },
  updated: plan.items.length - skipped.length,
  skipped,
  hasWrites: data.length > 0
} }];
